VALUES ('f2710000-0000-4000-8000-000000000004', 'a2710000-0000-4000-8000-000000000004', 'Bài 4: Cụm Si – Đô – Rê', 'published', 10, '[{"id":"d1","order":1,"logic":"DAN","type":"callout","title":"Cụm Si – Đô – Rê","interactive":{"variant":"teacher"},"content":"Thêm một <b>cụm nốt mới</b>: <b>Si – Đô – Rê</b>. Cụm này nằm <b>thấp hơn</b> Mi – Fa – Sol một chút trên khuông nhạc."},{"id":"d2","order":2,"logic":"NHAN","type":"note_show","title":"Si","interactive":{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4,"showStaff":true,"showFretboard":true,"caption":"<b>Si</b> — dây 2 <b>buông</b> (○). Trên khuông, Si nằm ở <b>dòng kẻ giữa</b>."}},{"id":"d3","order":3,"logic":"NHAN","type":"note_show","title":"Đô","interactive":{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"showStaff":true,"showFretboard":true,"caption":"<b>Đô</b> — cùng dây, bấm <b>ngăn 1</b>. Ngay trên Si một bậc."}},{"id":"d4","order":4,"logic":"NHAN","type":"note_show","title":"Rê","interactive":{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"showStaff":true,"showFretboard":true,"caption":"<b>Rê</b> — cùng dây, bấm <b>ngăn 3</b>. Cao hơn Đô một bậc nữa."}},{"id":"d5","order":5,"logic":"LAM","type":"note_practice","title":"Đánh theo: Si – Đô – Rê","interactive":{"notes":[{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6}]}},{"id":"d6","order":6,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình gảy được Si – Đô – Rê, tiếng rõ","Mình thấy cụm này nằm thấp hơn Mi – Fa – Sol trên khuông"]}},{"id":"d7","order":7,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tốt lắm! Giờ bạn có <b>2 cụm nốt</b>. Bài sau ta gộp chúng thành một <b>vùng nốt</b> liền mạch."}]'::jsonb)
