INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2710000-0000-4000-8000-000000000005', 'a2710000-0000-4000-8000-000000000005', 'Bài 5: Vùng nốt đầu tiên', 'published', 10, '[{"id":"v1","order":1,"logic":"DAN","type":"callout","title":"Vùng nốt đầu tiên","interactive":{"variant":"teacher"},"content":"Gộp 2 cụm lại, ta có <b>vùng nốt đầu tiên</b>: <b>Si – Đô – Rê – Mi – Fa – Sol</b>. Một <b>vùng âm thanh</b> liền mạch — hãy nghĩ theo vùng, đừng nghĩ theo dây."},{"id":"v2","order":2,"logic":"NGHI","type":"text","title":"6 nốt đi lên","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Sáu nốt đi <b>lên dần</b>: Si → Đô → Rê → Mi → Fa → Sol.<br/>Ba nốt đầu ở một dây, ba nốt sau ở dây cạnh — nhưng tai ta chỉ nghe <b>một vùng đi lên</b>.</p>"},{"id":"v3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo cả vùng","interactive":{"notes":[{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9}]}},{"id":"v4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi liền 6 nốt Si → Sol, đi lên đều","Mình thấy đây là một vùng âm thanh, không phải các dây rời rạc"]}},{"id":"v5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Rất vững! Bạn đã nắm <b>vùng nốt đầu tiên</b>. Bài cuối chương, ta đọc một <b>câu nhạc nhảy qua lại 2 dây</b> — năng lực thật khi tỉa nốt."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

