VALUES ('f2720000-0000-4000-8000-000000000001', 'a2720000-0000-4000-8000-000000000001', 'Bài 1: Cụm Sol – La', 'published', 10, '[{"id":"s1","order":1,"logic":"DAN","type":"callout","title":"Mở rộng xuống dưới","interactive":{"variant":"teacher"},"content":"Bạn đã chơi vùng nốt cao (Si → Sol). Giờ ta <b>mở rộng xuống dưới</b> — thêm 2 nốt <b>thấp hơn</b>: <b>Sol</b> và <b>La</b>, nằm ở dây dày hơn."},{"id":"s2","order":2,"logic":"NHAN","type":"note_show","title":"Sol (thấp)","interactive":{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"showStaff":true,"showFretboard":true,"caption":"<b>Sol</b> (thấp) — dây 3 <b>buông</b> (○). Nằm <b>thấp</b> trên khuông. Đây là Sol thấp hơn Sol cao đã học một quãng tám."}},{"id":"s3","order":3,"logic":"NHAN","type":"note_show","title":"La","interactive":{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"showStaff":true,"showFretboard":true,"caption":"<b>La</b> — cùng dây, bấm <b>ngăn 2</b>. Ngay trên Sol một bậc."}},{"id":"s4","order":4,"logic":"LAM","type":"note_practice","title":"Đánh theo: Sol – La – Si","interactive":{"notes":[{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2},{"label":"La","freq":220,"string":3,"fret":2,"staff":3},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2},{"label":"La","freq":220,"string":3,"fret":2,"staff":3},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4}]}},{"id":"s5","order":5,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình gảy được Sol – La, tiếng rõ","Mình nghe ra chúng THẤP hơn vùng nốt cao","Sol – La nối lên được Si (nốt đã học)"]}},{"id":"s6","order":6,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tốt! Hai nốt này nối liền xuống dưới vùng cũ. Bài sau thêm vài nốt thấp hơn nữa."}]'::jsonb)
