VALUES ('f2720000-0000-4000-8000-000000000002', 'a2720000-0000-4000-8000-000000000002', 'Bài 2: Cụm Rê – Mi – Fa', 'published', 10, '[{"id":"r1","order":1,"logic":"DAN","type":"callout","title":"Xuống thấp hơn nữa","interactive":{"variant":"teacher"},"content":"Thêm 3 nốt <b>thấp hơn nữa</b> ở dây dày hơn: <b>Rê – Mi – Fa</b>. Chúng nằm ở <b>đáy khuông nhạc</b>."},{"id":"r2","order":2,"logic":"NHAN","type":"note_show","title":"Rê","interactive":{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"showStaff":true,"showFretboard":true,"caption":"<b>Rê</b> — dây 4 <b>buông</b> (○). Nằm ngay <b>dưới dòng kẻ cuối</b> của khuông — nốt thấp nhất bài này."}},{"id":"r3","order":3,"logic":"NHAN","type":"note_show","title":"Mi (thấp)","interactive":{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"showStaff":true,"showFretboard":true,"caption":"<b>Mi</b> (thấp) — cùng dây, bấm <b>ngăn 2</b>. Nằm <b>trên dòng kẻ cuối</b>. Thấp hơn Mi cao đã học một quãng tám."}},{"id":"r4","order":4,"logic":"NHAN","type":"note_show","title":"Fa (thấp)","interactive":{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"showStaff":true,"showFretboard":true,"caption":"<b>Fa</b> (thấp) — cùng dây, bấm <b>ngăn 3</b>. Cao hơn Mi một bậc."}},{"id":"r5","order":5,"logic":"LAM","type":"note_practice","title":"Đánh theo: Rê – Mi – Fa","interactive":{"notes":[{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1}]}},{"id":"r6","order":6,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình gảy được Rê – Mi – Fa, tiếng rõ","Mình thấy Rê nằm dưới dòng kẻ cuối khuông"]}},{"id":"r7","order":7,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Giỏi! Giờ bạn đọc được cả nốt <b>dưới khuông</b>. Bài sau gộp thành một vùng liền mạch."}]'::jsonb)
