VALUES ('f3720000-0000-4000-8000-000000000004', 'a3720000-0000-4000-8000-000000000004', 'Bài 4: Đọc trọn cần đàn — hai quãng tám', 'published', 15, '[{"id":"o1","order":1,"logic":"DAN","type":"callout","title":"Bài tổng kết chương","interactive":{"variant":"teacher"},"content":"Đây là bài <b>tổng kết</b>: ta đọc <b>trọn cần đàn</b> ở thế tay 1 — từ <b>Mi trầm nhất</b> (dây 6) đi lên tận <b>Mi ở dây 1</b> (chính nốt đầu tiên bạn học ở đầu khoá!). Trọn <b>hai quãng tám</b>, qua cả <b>sáu dây</b>."},{"id":"o2","order":2,"logic":"NGHI","type":"text","title":"Cả cần đàn trong một câu","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Câu này chính là <b>âm giai nền tảng</b> ở thế tay 1: cứ vài nốt lại sang một dây. Đi thật <b>chậm</b>, đọc tên từng nốt. Thuộc câu này là bạn <b>đọc được nốt ở khắp cần đàn</b> — nền của mọi bài nhạc.</p>"},{"id":"o3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: trọn hai quãng tám","interactive":{"notes":[{"label":"Mi","freq":82.41,"string":6,"fret":0,"staff":-7},{"label":"Fa","freq":87.31,"string":6,"fret":1,"staff":-6},{"label":"Sol","freq":98,"string":6,"fret":3,"staff":-5},{"label":"La","freq":110,"string":5,"fret":0,"staff":-4},{"label":"Si","freq":123.47,"string":5,"fret":2,"staff":-3},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2},{"label":"La","freq":220,"string":3,"fret":2,"staff":3},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7}]}},{"id":"o4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi liền từ Mi (dây 6) lên Mi (dây 1), chuyển dây mượt","Mình đọc được tên nốt ở cả vùng trầm lẫn vùng cao","Mình nghe ra giai điệu đi lên trọn hai quãng tám"]}},{"id":"o5","order":5,"logic":"DAN","type":"callout","title":"Chúc mừng!","interactive":{"variant":"teacher"},"content":"Hoàn thành chương! Bạn đã <b>đọc được nốt khắp cần đàn</b> ở thế tay 1 — từ trầm nhất tới cao. Đây là nền tảng vững để sang <b>Chương 4 — Chơi bài hát</b>. Giỏi lắm!"}]'::jsonb)
