INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2730000-0000-4000-8000-000000000001', 'a2730000-0000-4000-8000-000000000001', 'Bài 2: Ode to Joy (Niềm Vui)', 'published', 15, '[{"id":"j1","order":1,"logic":"DAN","type":"callout","title":"Bài hát thật đầu tiên","interactive":{"variant":"teacher"},"content":"Thêm một <b>bài hát</b> nữa: <b>Ode to Joy</b> (Niềm Vui) của Beethoven — giai điệu quen thuộc. Nó chỉ dùng các nốt <b>Đô – Rê – Mi – Fa – Sol</b> đã học."},{"id":"j2","order":2,"logic":"NGHI","type":"text","title":"Giai điệu này quen mà!","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Cả bài đi quanh vùng <b>Đô → Sol</b>, có chuyển qua lại giữa <b>dây 1</b> (Mi-Fa-Sol) và <b>dây 2</b> (Đô-Rê).<br/>Chơi <b>đều từng nốt</b> cho đúng cao độ trước — <b>nhịp điệu ngắn-dài</b> để bài sau.</p>"},{"id":"j3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: Ode to Joy","interactive":{"notes":[{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1.5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":0.5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":2}]}},{"id":"j4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi hết được giai điệu, đúng các nốt","Mình nhận ra đúng bài Ode to Joy quen thuộc","Mình chuyển dây 1↔2 mà tiếng vẫn đều"]}},{"id":"j5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tuyệt vời! Hai bài hát bạn đã chơi được chỉ từ những nốt đã học. Đây là lý do ta học nốt: để chơi được nhạc thật."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

