INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f2730000-0000-4000-8000-000000000004', 'a2730000-0000-4000-8000-000000000004', 'Bài 4: Ngôi Sao Nhỏ (Twinkle Twinkle)', 'published', 15, '[{"id":"w1","order":1,"logic":"DAN","type":"callout","title":"Chơi: Ngôi Sao Nhỏ","interactive":{"variant":"teacher"},"content":"\"Twinkle Twinkle Little Star\" — giai điệu ru quen thuộc khắp thế giới. Bài này cũng ở <b>vùng trầm</b> (dây 3-4-5), toàn nốt tự nhiên, rất hợp để luyện đọc nốt cho <b>đều và chắc</b>."},{"id":"w2","order":2,"logic":"NGHI","type":"text","title":"Từng cặp nốt","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Giai điệu đi thành <b>từng cặp</b> (Đô-Đô, Sol-Sol, La-La…) nên rất dễ theo. Cả bài quanh <b>Đô – Rê – Mi – Fa – Sol – La</b>. Nghe mẫu một lượt rồi đàn theo <b>chậm</b>, giữ nhịp cho đều.</p>"},{"id":"w3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: Ngôi Sao Nhỏ","interactive":{"notes":[{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":2},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":2},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":2},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":2},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":2},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":2}]}},{"id":"w4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi trọn bài, các cặp nốt đều tay","Mình chuyển dây 3-4-5 mượt, không vấp","Mình nghe ra đúng giai điệu Ngôi Sao Nhỏ"]}},{"id":"w5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Giỏi lắm! Thêm một bài hát trọn vẹn vào ''kho'' của bạn. Chơi được những giai điệu quen thế này nghĩa là bạn đã <b>đọc nốt và chuyển dây</b> thành thạo rồi."}]'::jsonb)
