-- Bài 1: Nốt đen & nốt trắng
INSERT INTO edu_course_lessons (id, module_id, title, lesson_type, order_index, is_published, tier)
VALUES ('a5720000-0000-4000-8000-000000000001', 'c5720000-0000-4000-8000-000000000001', 'Bài 1: Nốt đen & nốt trắng', 'flow', 1, true, 'free')
ON CONFLICT (id) DO UPDATE SET module_id = EXCLUDED.module_id, title = EXCLUDED.title, order_index = EXCLUDED.order_index, lesson_type = 'flow', is_published = true;

INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f5720000-0000-4000-8000-000000000001', 'a5720000-0000-4000-8000-000000000001', 'Bài 1: Nốt đen & nốt trắng', 'published', 12, '[{"id":"n1","order":1,"logic":"DAN","type":"callout","title":"Nốt dài, nốt ngắn","interactive":{"variant":"teacher"},"content":"Tới giờ ta chơi mọi nốt <b>đều nhau</b> — nhưng thật ra mỗi nốt có <b>độ dài riêng</b>. Có nốt ngân ngắn, có nốt ngân dài. Bắt đầu bằng <b>hai loại cơ bản</b> nhất: nốt <b>đen</b> và nốt <b>trắng</b>."},{"id":"n2","order":2,"logic":"NHAN","type":"note_show","title":"Nốt đen — 1 phách","interactive":{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1,"showStaff":true,"showFretboard":false,"caption":"<b>Nốt đen</b>: đầu nốt <b>đặc</b>, có đuôi. Ngân <b>1 phách</b> — đây là đơn vị đếm cơ bản (\"một\")."}},{"id":"n3","order":3,"logic":"NHAN","type":"note_show","title":"Nốt trắng — 2 phách","interactive":{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":2,"showStaff":true,"showFretboard":false,"caption":"<b>Nốt trắng</b>: đầu nốt <b>rỗng</b>, có đuôi. Ngân <b>2 phách</b> — dài <b>gấp đôi</b> nốt đen. Vẫn là nốt Mi, chỉ khác <b>độ dài</b>."}},{"id":"n4","order":4,"logic":"NGHI","type":"text","title":"Đếm phách","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Cách cảm nhận: nốt <b>đen</b> đếm <b>\"1\"</b> rồi gảy nốt kế; nốt <b>trắng</b> giữ ngân qua <b>\"1 – 2\"</b> mới sang nốt kế. Bấm <b>Nghe mẫu</b> ở dưới để nghe nốt trắng <b>ngân lâu gấp đôi</b>.</p>"},{"id":"n5","order":5,"logic":"LAM","type":"note_practice","title":"Đánh theo: đen – đen – trắng","interactive":{"showDur":true,"notes":[{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":2},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Si","freq":246.94,"string":2,"fret":0,"staff":4,"dur":2}]}},{"id":"n6","order":6,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình phân biệt được nốt đen (đầu đặc) và nốt trắng (đầu rỗng)","Khi Nghe mẫu, mình nghe nốt trắng ngân lâu gấp đôi nốt đen"]}},{"id":"n7","order":7,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tốt lắm! Bạn vừa đọc được <b>độ dài</b> của nốt — không chỉ cao độ. Bài sau ta thêm nốt <b>tròn</b> (ngân 4 phách) và ghép cả ba loại."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

-- Bài 2: Nốt tròn & ghép ba loại
INSERT INTO edu_course_lessons (id, module_id, title, lesson_type, order_index, is_published, tier)
VALUES ('a5720000-0000-4000-8000-000000000002', 'c5720000-0000-4000-8000-000000000001', 'Bài 2: Nốt tròn & ghép ba loại', 'flow', 2, true, 'free')
ON CONFLICT (id) DO UPDATE SET module_id = EXCLUDED.module_id, title = EXCLUDED.title, order_index = EXCLUDED.order_index, lesson_type = 'flow', is_published = true;

INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f5720000-0000-4000-8000-000000000002', 'a5720000-0000-4000-8000-000000000002', 'Bài 2: Nốt tròn & ghép ba loại', 'published', 12, '[{"id":"o1","order":1,"logic":"DAN","type":"callout","title":"Nốt dài nhất","interactive":{"variant":"teacher"},"content":"Thêm loại nốt <b>dài nhất</b>: nốt <b>tròn</b>. Nó ngân tận <b>4 phách</b> — bằng <b>hai nốt trắng</b> hoặc <b>bốn nốt đen</b> cộng lại. Sau đó ta sẽ ghép cả ba loại vào một câu."},{"id":"o2","order":2,"logic":"NHAN","type":"note_show","title":"Nốt tròn — 4 phách","interactive":{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":4,"showStaff":true,"showFretboard":false,"caption":"<b>Nốt tròn</b>: đầu nốt <b>rỗng</b> và <b>KHÔNG có đuôi</b>. Ngân <b>4 phách</b> — giữ thật lâu, đếm trọn \"1 – 2 – 3 – 4\"."}},{"id":"o3","order":3,"logic":"NGHI","type":"text","title":"Bảng độ dài","content":"<p style=\"font-size:16px;line-height:1.75;margin:0;color:#3A352F\">Ba loại đã học:<br/>• Nốt <b>đen</b> (đầu đặc) = <b>1</b> phách<br/>• Nốt <b>trắng</b> (đầu rỗng, có đuôi) = <b>2</b> phách<br/>• Nốt <b>tròn</b> (đầu rỗng, không đuôi) = <b>4</b> phách<br/>Bấm <b>Nghe mẫu</b>: nghe theo tiếng gõ metronome để cảm mỗi loại giữ mấy phách.</p>"},{"id":"o4","order":4,"logic":"LAM","type":"note_practice","title":"Đánh theo: ghép đen – trắng – tròn","interactive":{"showDur":true,"notes":[{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":2},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":2},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":4}]}},{"id":"o5","order":5,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình phân biệt được đen (1) – trắng (2) – tròn (4) phách","Mình nghe nốt tròn ngân dài nhất, trọn 4 tiếng gõ","Mình đàn theo được cả câu, giữ đúng độ dài từng nốt"]}},{"id":"o6","order":6,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tuyệt vời! Giờ bạn đọc được <b>ba độ dài</b> cơ bản. Bài sau thêm một thứ nữa: <b>dấu lặng</b> — khoảng <b>nghỉ</b> (im lặng) cũng là một phần của nhạc."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

