INSERT INTO edu_course_lessons (id, module_id, title, lesson_type, order_index, is_published, tier)
VALUES ('a5720000-0000-4000-8000-000000000003', 'c5720000-0000-4000-8000-000000000001', 'Bài 3: Dấu lặng — khoảng nghỉ', 'flow', 3, true, 'free')
