INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f5720000-0000-4000-8000-000000000003', 'a5720000-0000-4000-8000-000000000003', 'Bài 3: Dấu lặng — khoảng nghỉ', 'published', 12, '[{"id":"l1","order":1,"logic":"DAN","type":"callout","title":"Im lặng cũng là nhạc","interactive":{"variant":"teacher"},"content":"Nhạc không chỉ có tiếng đàn — có những lúc phải <b>nghỉ</b> (im lặng). Khoảng nghỉ đó ghi bằng <b>dấu lặng</b>, và nó cũng có <b>độ dài</b> đúng như nốt vậy."},{"id":"l2","order":2,"logic":"NGHI","type":"text","title":"Dấu lặng đen = nghỉ 1 phách","content":"<p style=\"font-size:16px;line-height:1.75;margin:0;color:#3A352F\">Loại cơ bản là <b>dấu lặng đen</b> — <b>nghỉ 1 phách</b> (im bằng một nốt đen). Khi <b>Nghe mẫu</b>, tới dấu lặng thì đàn <b>im</b> nhưng metronome <b>vẫn gõ</b> — bạn đếm tiếng gõ và giữ im đúng <b>1 phách</b> rồi mới chơi nốt kế.</p>"},{"id":"l3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: có dấu lặng","interactive":{"showDur":true,"notes":[{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"","freq":0,"rest":true,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":2}]}},{"id":"l4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình nhận ra dấu lặng trên khuông (không phải nốt)","Tới dấu lặng mình giữ IM đúng 1 phách, metronome vẫn gõ","Mình vào lại nốt kế đúng nhịp sau khoảng nghỉ"]}},{"id":"l5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Giỏi lắm! Giờ bạn đọc được cả <b>nốt</b> lẫn <b>khoảng nghỉ</b> — đủ để đọc một bản nhạc thật. Bài cuối chương: <b>chơi lại một bài quen thuộc đúng nhịp</b>."}]'::jsonb)
ON CONFLICT (id) DO UPDATE SET lesson_id = EXCLUDED.lesson_id, title = EXCLUDED.title, status = EXCLUDED.status, reward_xp = EXCLUDED.reward_xp, slides = EXCLUDED.slides;

