INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f5720000-0000-4000-8000-000000000004', 'a5720000-0000-4000-8000-000000000004', 'Bài 4: Ngôi Sao Nhỏ — đọc đúng nhịp', 'published', 15, '[{"id":"z1","order":1,"logic":"DAN","type":"callout","title":"Bài tổng kết chương","interactive":{"variant":"teacher"},"content":"Bài cuối chương: chơi lại <b>Ngôi Sao Nhỏ</b> — nhưng lần này <b>đọc đúng nhịp</b>! Giờ bạn nhìn ra nốt nào <b>đen</b> (ngắn), nốt nào <b>trắng</b> (dài gấp đôi). Nghe khác hẳn lúc đàn đều đều."},{"id":"z2","order":2,"logic":"NGHI","type":"text","title":"Để ý cuối mỗi câu","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Nhìn kỹ: <b>cuối mỗi câu</b> là một nốt <b>trắng</b> (đầu rỗng) — ngân <b>2 phách</b>, như chỗ lấy hơi của giai điệu. Bấm <b>Nghe mẫu</b>: có <b>đếm lấy đà</b> và <b>metronome</b> — đàn theo, giữ nốt trắng cho đủ 2 tiếng gõ.</p>"},{"id":"z3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: Ngôi Sao Nhỏ (đúng nhịp)","interactive":{"showDur":true,"notes":[{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":2},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":2},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":2},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":2},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":1},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":2},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Fa","freq":174.61,"string":4,"fret":3,"staff":1,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Rê","freq":146.83,"string":4,"fret":0,"staff":-1,"dur":1},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2,"dur":2}]}},{"id":"z4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi trọn bài, giữ nốt trắng đủ 2 phách","Mình theo được metronome, không vội không chậm","Mình nghe bài vang ĐÚNG như Ngôi Sao Nhỏ thật (không còn đều đều)"]}},{"id":"z5","order":5,"logic":"DAN","type":"callout","title":"Chúc mừng bạn!","interactive":{"variant":"teacher"},"content":"Hoàn thành Chương 5! Giờ bạn đọc được cả <b>cao độ</b> (nốt nào) lẫn <b>trường độ</b> (dài bao lâu) — tức là <b>đọc được một bản nhạc thật</b>. Đây là một cột mốc lớn trên hành trình tỉa nốt của bạn. 🎸"}]'::jsonb)
