INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f5720000-0000-4000-8000-000000000005', 'a5720000-0000-4000-8000-000000000005', 'Bài 5: Nốt móc đơn (nửa phách)', 'published', 14, '[{"id":"c1","order":1,"logic":"DAN","type":"callout","title":"Nốt ngắn hơn — nốt móc đơn","interactive":{"variant":"teacher"},"content":"Loại cuối trong bộ trường độ: nốt <b>móc đơn</b> — ngắn nhất, chỉ <b>nửa phách</b>. Đầu nốt <b>đặc</b>, có đuôi và thêm một <b>dấu móc</b> nhỏ. <b>Hai nốt móc đơn</b> ghép lại = <b>một nốt đen</b>."},{"id":"c2","order":2,"logic":"NHAN","type":"note_show","title":"Nốt móc đơn — ½ phách","interactive":{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":0.5,"showStaff":true,"showFretboard":false,"caption":"<b>Nốt móc đơn</b>: đầu đặc, có đuôi + <b>dấu móc</b>. Ngân <b>nửa phách</b> — nhanh gấp đôi nốt đen. Thường đi thành <b>cặp đôi</b>."}},{"id":"c3","order":3,"logic":"NGHI","type":"text","title":"Đếm \"1-và 2-và\"","content":"<p style=\"font-size:16px;line-height:1.75;margin:0;color:#3A352F\">Mỗi phách chia làm <b>hai nửa</b>: đếm <b>\"1 - và - 2 - và\"</b>. Nốt đen = cả phách (\"1\"); <b>hai nốt móc đơn</b> = \"1 - và\" (hai nửa). Nghe mẫu để cảm: chỗ móc đơn chạy <b>nhanh gấp đôi</b>.</p>"},{"id":"c4","order":4,"logic":"LAM","type":"note_practice","title":"Đánh theo: có nốt móc đơn","interactive":{"showDur":true,"beatsPerBar":4,"notes":[{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":0.5},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":0.5},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":0.5},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":0.5},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":0.5},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":0.5},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":2}]}},{"id":"c5","order":5,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình nhận ra nốt móc đơn (có dấu móc ở đuôi)","Mình nghe cặp móc đơn chạy nhanh gấp đôi nốt đen","Mỗi ô mình vẫn giữ đủ 4 phách"]}},{"id":"c6","order":6,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Tuyệt! Giờ bạn đọc được đủ <b>bốn loại trường độ</b>: tròn, trắng, đen, móc đơn — chơi được nhịp điệu của gần như mọi bài hát. Bài sau ta <b>vận dụng</b> vào một bài Việt quen thuộc!"}]'::jsonb)
