VALUES ('f6720000-0000-4000-8000-000000000002', 'a6720000-0000-4000-8000-000000000002', 'Bài 2: Nhịp 3/4 (valse)', 'published', 12, '[{"id":"v1","order":1,"logic":"DAN","type":"callout","title":"Nhịp ba — điệu valse","interactive":{"variant":"teacher"},"content":"Đổi sang <b>nhịp 3/4</b>: mỗi ô chỉ có <b>3 phách</b>. Đây là nhịp của điệu <b>valse</b> (nhịp ba) — đếm <b>1-2-3, 1-2-3</b>. Để ý: lấy đà giờ chỉ đếm <b>3</b>, không phải 4."},{"id":"v2","order":2,"logic":"NGHI","type":"text","title":"Mỗi ô 3 phách","content":"<p style=\"font-size:16px;line-height:1.75;margin:0;color:#3A352F\">Số <b>3/4</b> (số 3 trên) = <b>3 phách mỗi ô</b>. Ví dụ: ô đầu <b>3 nốt đen</b> (1+1+1), ô sau <b>1 đen + 1 trắng</b> (1+2) — đều đủ <b>3 phách</b>. Nghe mẫu đếm 3 phách lấy đà.</p>"},{"id":"v3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: nhịp 3/4","interactive":{"showDur":true,"beatsPerBar":3,"notes":[{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":2}]}},{"id":"v4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình thấy mỗi ô chỉ có 3 phách","Lấy đà đếm đúng 3 (không phải 4)","Mình cảm được nhịp đung-đưa của valse"]}},{"id":"v5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Hay lắm! Cùng một nốt nhưng nhịp khác nhau cho <b>cảm giác khác hẳn</b>. Bài sau: <b>nhịp 2/4</b> — nhịp hành khúc, mỗi ô 2 phách."}]'::jsonb)
