INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f6720000-0000-4000-8000-000000000003', 'a6720000-0000-4000-8000-000000000003', 'Bài 3: Nhịp 2/4 (hành khúc)', 'published', 12, '[{"id":"h1","order":1,"logic":"DAN","type":"callout","title":"Nhịp hai — bước đều","interactive":{"variant":"teacher"},"content":"<b>Nhịp 2/4</b>: mỗi ô <b>2 phách</b> — nhịp của <b>hành khúc</b>, bước đều \"1-2, 1-2\" như đi diễu hành. Lấy đà đếm <b>2</b>."},{"id":"h2","order":2,"logic":"NGHI","type":"text","title":"Mỗi ô 2 phách","content":"<p style=\"font-size:16px;line-height:1.75;margin:0;color:#3A352F\">Số <b>2/4</b> = <b>2 phách mỗi ô</b>. Ví dụ dưới có <b>3 ô</b>: hai ô đầu mỗi ô <b>2 nốt đen</b> (1+1), ô cuối <b>1 nốt trắng</b> (2) — đều đủ 2 phách. Bước nào cũng chắc nịch \"1-2\".</p>"},{"id":"h3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: nhịp 2/4","interactive":{"showDur":true,"beatsPerBar":2,"notes":[{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":2}]}},{"id":"h4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình thấy mỗi ô chỉ 2 phách","Lấy đà đếm đúng 2","Mình giữ bước đều 1-2 theo metronome"]}},{"id":"h5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Giỏi! Giờ bạn phân biệt được <b>2/4 · 3/4 · 4/4</b>. Bài cuối chương: đọc một <b>bài hát thật</b> có đủ số chỉ nhịp và vạch nhịp."}]'::jsonb)
