INSERT INTO flows (id, lesson_id, title, status, reward_xp, slides)
VALUES ('f6720000-0000-4000-8000-000000000004', 'a6720000-0000-4000-8000-000000000004', 'Bài 4: Đọc bài có ô nhịp — Ode to Joy', 'published', 15, '[{"id":"b1","order":1,"logic":"DAN","type":"callout","title":"Bản nhạc hoàn chỉnh","interactive":{"variant":"teacher"},"content":"Bài tổng kết: đọc <b>Ode to Joy</b> như một <b>bản nhạc thật</b> — có <b>khóa Sol</b>, <b>số chỉ nhịp 4/4</b>, <b>vạch nhịp</b> chia ô, và nốt <b>đen/trắng</b>. Bạn đã đủ ''đồ nghề'' để đọc nó!"},{"id":"b2","order":2,"logic":"NGHI","type":"text","title":"Bốn ô nhịp 4/4","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Bài này có <b>4 ô</b>, mỗi ô 4 phách. Nhìn vạch nhịp để biết mình đang ở ô nào. Câu kết là một <b>nốt trắng</b> ngân 2 phách. Nghe mẫu (đếm 4 lấy đà) rồi đàn theo cho <b>chắc từng ô</b>.</p>"},{"id":"b3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: Ode to Joy (4/4)","interactive":{"showDur":true,"beatsPerBar":4,"notes":[{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":2}]}},{"id":"b4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình đọc được cả bài: khóa Sol + 4/4 + vạch nhịp + nốt đen/trắng","Mình chơi đúng từng ô, mỗi ô đủ 4 phách","Mình nghe ra giai điệu Ode to Joy, giữ nhịp đều"]}},{"id":"b5","order":5,"logic":"DAN","type":"callout","title":"Chúc mừng!","interactive":{"variant":"teacher"},"content":"Hoàn thành Chương 6! Giờ bạn đọc được một <b>bản nhạc chuẩn</b> đầy đủ: cao độ, trường độ, và ô nhịp. Bạn đã thật sự <b>biết đọc nhạc</b> rồi. 🎉"}]'::jsonb)
