VALUES ('f7720000-0000-4000-8000-000000000001', 'a7720000-0000-4000-8000-000000000001', 'Bài 1: Ôn cao độ — đọc nốt khắp cần đàn', 'published', 12, '[{"id":"a1","order":1,"logic":"DAN","type":"callout","title":"Ôn lại: đọc nốt mọi dây","interactive":{"variant":"teacher"},"content":"Bắt đầu ôn tập! Câu này là <b>hợp âm rải Đô trưởng</b> đi lên qua <b>cả sáu dây</b> — mỗi dây một nốt (Sol–Đô–Mi–Sol–Đô–Mi). Đọc tên nốt và tìm đúng vị trí trên từng dây nhé."},{"id":"a2","order":2,"logic":"LAM","type":"note_practice","title":"Đánh theo: rải qua 6 dây","interactive":{"notes":[{"label":"Sol","freq":98,"string":6,"fret":3,"staff":-5},{"label":"Đô","freq":130.81,"string":5,"fret":3,"staff":-2},{"label":"Mi","freq":164.81,"string":4,"fret":2,"staff":0},{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7}]}},{"id":"a3","order":3,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình đọc và tìm đúng nốt trên cả 6 dây","Mình chuyển từ dây trầm nhất lên dây cao mượt"]}},{"id":"a4","order":4,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Đọc nốt khắp cần đàn — bạn làm được rồi! Bài sau ôn <b>trường độ và ô nhịp</b>."}]'::jsonb)
