VALUES ('f7720000-0000-4000-8000-000000000003', 'a7720000-0000-4000-8000-000000000003', 'Bài 3: Vận dụng — Ode to Joy cùng ban nhạc', 'published', 25, '[{"id":"t1","order":1,"logic":"DAN","type":"callout","title":"Ôn tập tổng hợp","interactive":{"variant":"teacher"},"content":"Giờ chơi cho <b>đã tai</b>: đọc trọn <b>Ode to Joy</b> (8 ô) nhưng lần này có cả <b>ban nhạc đệm</b> — trống, bass và strings — chạy nền phía dưới. Bạn tỉa giai điệu, ban nhạc lo phần còn lại!"},{"id":"t2","order":2,"logic":"NGHI","type":"text","title":"Trọn 8 ô","content":"<p style=\"font-size:16px;line-height:1.7;margin:0;color:#3A352F\">Bài chia <b>8 ô</b> nhịp 4/4. Bấm <b>Nghe mẫu</b>: sau 4 phách đếm lấy đà, <b>ban nhạc vào</b> và giai điệu chạy theo. Nghe cho quen rồi <b>đàn theo</b> — giữ nhịp đều cùng trống nhé.</p>"},{"id":"t3","order":3,"logic":"LAM","type":"note_practice","title":"Đánh theo: Ode to Joy (có ban nhạc)","interactive":{"showDur":true,"beatsPerBar":4,"notes":[{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":2},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Sol","freq":392,"string":1,"fret":3,"staff":9,"dur":1},{"label":"Fa","freq":349.23,"string":1,"fret":1,"staff":8,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Mi","freq":329.63,"string":1,"fret":0,"staff":7,"dur":1},{"label":"Rê","freq":293.66,"string":2,"fret":3,"staff":6,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":1},{"label":"Đô","freq":261.63,"string":2,"fret":1,"staff":5,"dur":2}],"chords":[{"bass":65.41,"pad":[130.81,164.81,196]},{"bass":98,"pad":[146.83,196,246.94]},{"bass":65.41,"pad":[130.81,164.81,196]},{"bass":98,"pad":[146.83,196,246.94]},{"bass":65.41,"pad":[130.81,164.81,196]},{"bass":98,"pad":[146.83,196,246.94]},{"bass":65.41,"pad":[130.81,164.81,196]},{"bass":65.41,"pad":[130.81,164.81,196]}],"scored":true}},{"id":"t4","order":4,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình chơi theo được cùng ban nhạc, không lạc nhịp","Mình đọc trọn bản nhạc: cao độ + trường độ + ô nhịp","Nghe vui tai như đang biểu diễn thật"]}},{"id":"t5","order":5,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"<b>Rất giỏi!</b> Bạn vừa đọc trọn một bản nhạc thật — kết hợp cao độ, trường độ và ô nhịp. Đây là cột mốc đáng tự hào, nhưng <b>hành trình còn tiếp</b>: phía trước là những giai điệu hay hơn, kỹ thuật mới và nhiều bài hát bạn yêu thích. Tiếp tục nhé! 🎸"}]'::jsonb)
