VALUES ('f8720000-0000-4000-8000-000000000001', 'a8720000-0000-4000-8000-000000000001', 'Bài 1: Dấu thăng (#) & Sol#', 'published', 12, '[{"id":"s1","order":1,"logic":"DAN","type":"callout","title":"Dấu thăng # là gì?","interactive":{"variant":"teacher"},"content":"Dấu <b>thăng (#)</b> đặt <b>trước</b> một nốt = <b>nâng nửa cung</b> = trên đàn bấm <b>cao hơn 1 ngăn</b>. Hãy so sánh <b>Sol</b> và <b>Sol#</b> để thấy rõ."},{"id":"s2","order":2,"logic":"NHAN","type":"note_show","title":"Sol thường","interactive":{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"showStaff":true,"showFretboard":true,"caption":"<b>Sol thường</b> — dây 3 <b>buông</b> (○), không có dấu gì. Nghe kỹ cao độ của nó."}},{"id":"s3","order":3,"logic":"NHAN","type":"note_show","title":"Sol thăng (Sol#)","interactive":{"label":"Sol#","freq":207.65,"string":3,"fret":1,"staff":2,"acc":"#","showStaff":true,"showFretboard":true,"caption":"<b>Sol#</b> — có dấu <b>#</b> trước nốt (cùng dòng với Sol). Bấm <b>cao hơn 1 ngăn</b> (dây 3 ngăn 1). Nghe <b>cao hơn Sol nửa cung</b>."}},{"id":"s4","order":4,"logic":"NHAN","type":"note_show","title":"Sol# ở dây 1","interactive":{"label":"Sol#","freq":415.3,"string":1,"fret":4,"staff":9,"acc":"#","showStaff":true,"showFretboard":true,"caption":"Sol# cũng có ở <b>dây 1</b>: Sol là dây 1 <b>ngăn 3</b> → thêm # → bấm <b>ngăn 4</b>."}},{"id":"s5","order":5,"logic":"NHAN","type":"note_show","title":"Sol# ở dây 6","interactive":{"label":"Sol#","freq":103.83,"string":6,"fret":4,"staff":-5,"acc":"#","showStaff":true,"showFretboard":true,"caption":"Và ở <b>dây 6</b> (trầm nhất): Sol là dây 6 <b>ngăn 3</b> → thêm # → bấm <b>ngăn 4</b>."}},{"id":"s6","order":6,"logic":"LAM","type":"note_practice","title":"Đánh theo: Sol → Sol# → La","interactive":{"showDur":true,"notes":[{"label":"Sol","freq":196,"string":3,"fret":0,"staff":2,"dur":1},{"label":"Sol#","freq":207.65,"string":3,"fret":1,"staff":2,"acc":"#","dur":1},{"label":"La","freq":220,"string":3,"fret":2,"staff":3,"dur":2}]}},{"id":"s7","order":7,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình phân biệt được Sol và Sol# (Sol# cao hơn nửa cung)","Mình biết # = bấm cao hơn 1 ngăn","Mình tìm được Sol# ở dây 3, dây 1, dây 6"]}},{"id":"s8","order":8,"logic":"DAN","type":"callout","title":"Lời thầy","interactive":{"variant":"teacher"},"content":"Giỏi! Thấy dấu <b>#</b> là bấm <b>cao hơn 1 ngăn</b>. Bài sau ta chơi thử một <b>đoạn nhạc ngắn có Sol#</b>."}]'::jsonb)
